import{_ as a,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"99B. Examination Leave Rpn And Pen","description":"","frontmatter":{"title":"99B. Examination Leave Rpn And Pen","eba":"Mental Health Services 2024-2028","topics":["leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/education-pd/99B-examination-leave-rpn-and-pen.md","filePath":"ebas/mental-health/rpn-pen-mho/education-pd/99B-examination-leave-rpn-and-pen.md"}'),r={name:"ebas/mental-health/rpn-pen-mho/education-pd/99B-examination-leave-rpn-and-pen.md"};function i(s,e,l,p,m,d){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_99b-examination-leave-rpn-and-pen" tabindex="-1">99B. Examination Leave Rpn And Pen <a class="header-anchor" href="#_99b-examination-leave-rpn-and-pen" aria-label="Permalink to &quot;99B. Examination Leave Rpn And Pen&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>99B.1</strong> Entitlement</p><p><strong>(a)</strong> An eligible RPN or PEN shall be entitled to five days paid leave in any one year for the purposes of undertaking and/or preparing for examinations in an eligible course of study. Examinations include major assessment tasks, take home exams and other methods of student assessment.</p><p><strong>(b)</strong> Leave entitlements pursuant to this clause will not accumulate from year to year.</p><p><strong>99B.2</strong> Employee eligibility</p><p>To be eligible for examination leave, an Employee must:</p><p><strong>(a)</strong> be employed to work on average, at least three shifts or 24 hours per week; and</p><p><strong>(b)</strong> have been employed for not less than eighteen (18) months by their current Employer immediately prior to taking of examination leave.</p><p><strong>99B.3</strong> Eligible course of study</p><p><strong>(a)</strong> To be eligible for examination leave, the course of study must be:</p><p><strong>(i)</strong> related to the Employee&#39;s Classification in Grades duty requirements; and</p><p><strong>(ii)</strong> relevant to advancement through the career structure and to employment at the establishment.</p><p><strong>(b)</strong> Such a course of study would normally be undertaken in a tertiary institution.</p><p><strong>99B.4</strong> Time of taking leave</p><p>Examination leave will be taken at a time that is agreed between the Employer and the Employee. The Employer will not unreasonably withhold approval for such leave.</p><p><strong>99B.5</strong> Payment</p><p>A day for the purposes of examination leave is the Employee&#39;s normal shift length.</p><p><strong>99B.6</strong> Staff Replacement</p><p>All absences resulting from approved leave under clauses 99B (examination leave) will be backfilled in clinical areas where that Employee would ordinarily have a patient allocation.</p>',20)])])}const c=a(r,[["render",i]]);export{u as __pageData,c as default};
